#include <stdio.h>
int daysNeeded(int* weights, int weightsSize, int capacity) {
    int days = 1, currentLoad = 0;
    for (int i = 0; i < weightsSize; i++) {
        if (currentLoad + weights[i] > capacity) {
            days++;
            currentLoad = weights[i];
        } else {
            currentLoad += weights[i];
        }
    }
    return days;
}

int shipWithinDays(int* weights, int weightsSize, int d) {
    int left = weights[0], right = 0;
    for (int i = 0; i < weightsSize; i++) {
        left = (left > weights[i]) ? left : weights[i];
        right += weights[i];
    }
    while (left < right) {
        int mid = left + (right - left) / 2;
        if (daysNeeded(weights, weightsSize, mid) <= d) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }
    return left;
}

int main() {
    int weights[] = {5, 4, 5, 2, 3, 4, 5, 6};
    int d = 5;
    printf("%d\n", shipWithinDays(weights, 8, d));
    return 0;
}

